#include <iostream>

class Circle {
    double _r;
public:
    Circle( double  _in_r ) : _r(_in_r) {}
    double get_r_val() const {
        return _r;
    }
    double calculate_circ_area() const {
        return 3.14159 * _r * _r;
    }
};

int main() {
    std::cout.precision(12);
    double r_test;
    while (std::cin >> r_test) {
        Circle c(r_test);
        std::cout << c.calculate_circ_area() << std::endl;
    }
    return 0;
}
